import{_ as s,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function t(d,e){return n(),i("div",null,e[0]||(e[0]=[a(`<p>测试文件使用<code>.test.js</code>结尾，测试框架会自动识别这样结尾的文件当做测试运行</p><p><strong>单元测试unit testing</strong> 在软件中最小可测试单元进行检查和验证 简单来说就是模块，对导出的模块进行测试</p><p>每个测试文件默认都是使用describe包裹进行分组的，只不过每个文件最外层默认省略了 生命周期是针对于describe的，如果多层describe嵌套则会像栈一样先执行外层的before后执行内层的before，而对于after则是先执行内层的after，后执行外层的after</p><h1 id="开启测试" tabindex="-1"><a class="header-anchor" href="#开启测试"><span>开启测试</span></a></h1><p>普通文件中使用到的函数（被测试的函数）</p><div class="language-add.ts line-numbers-mode" data-highlighter="shiki" data-ext="add.ts" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export function add(a:number,b:number):number{</span></span>
<span class="line"><span>	return a+b</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>测试函数</p><div class="language-add.test.ts line-numbers-mode" data-highlighter="shiki" data-ext="add.test.ts" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import {add} from &#39;add.ts&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test(&#39;加法&#39;,()=&gt;{</span></span>
<span class="line"><span>	expect(add(1,2)).toBe(3)</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>test：测试函数，第一个参数是测试名，第二个参数是回调函数，在里面执行测试的逻辑</li><li>expect：传入要被测试的函数及其参数</li><li>toBe：传入期望的值，如果expect接收到的值与toBe中的值不符就会报错（测试未通过），如果相同则测试通过。绝对相等，是地址的比较，如果两个对象的数据一样，是浅拷贝的话就可以通过测试，深拷贝关系就无法通过测试</li><li>toEqual：和toBe类似，是值的比较，只要值相等就可以通过测试</li><li>toBeNull：不需要传入参数，如果expect接收的值为null就通过测试</li><li>toBeUndefined：匹配undefined</li><li>toBeDefined：匹配有定义的值</li><li>toBeTruthy：匹配的值如果转成布尔类型是true就可以通过测试</li><li>toBeFalsy：匹配的值转成布尔类型是false可以通过测试</li><li>toBeGreaterThan：匹配的值大于传递的值就可以通过</li><li>toBeLessThan：匹配的值小于传递的值就可以通过</li><li>toBeGreaterOrEqual：匹配的值大于等于传递的值就可以通过</li><li>toBeCloseTo：和toBe相同但解决了浮点数精度问题</li><li>toMatch：匹配的字符串中有传入的字符串就通过</li><li>toContain：匹配的数组中有传入的元素就通过</li></ol><p>test中only定义的单元测试会会跳过其他同级的单元测试，只测试only声明的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>test.only(&#39;1&#39;,()=&gt;{})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="生命周期函数" tabindex="-1"><a class="header-anchor" href="#生命周期函数"><span>生命周期函数</span></a></h1><ul><li>beforeAll：在所有测试用例之前执行</li><li>beforeEach：在每个测试用例执行前都会执行</li><li>afterEach：在每个测试用例执行完成后都会执行</li><li>afterAll：在所有测试用例执行完成后执行</li></ul><h1 id="分组" tabindex="-1"><a class="header-anchor" href="#分组"><span>分组</span></a></h1><p>多个方法共同测试时查看起来比较混乱，可以将逻辑相关的测试分为同一组中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>describe(&#39;分组1&#39;,()=&gt;{</span></span>
<span class="line"><span>	test(&#39;测试1&#39;,()=&gt;{</span></span>
<span class="line"><span>		// ...</span></span>
<span class="line"><span>	})</span></span>
<span class="line"><span>	test(&#39;测试2&#39;,()=&gt;{</span></span>
<span class="line"><span>		// ...</span></span>
<span class="line"><span>	})</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在分组后对于在生命周期中的执行逻辑也是分组在上的先执行</p>`,17)]))}const p=s(l,[["render",t]]),c=JSON.parse('{"path":"/front/vue/9/","title":"9 Vitest","lang":"zh-CN","frontmatter":{"title":"9 Vitest","createTime":"2025/06/21 18:16:58","permalink":"/front/vue/9/"},"readingTime":{"minutes":2.49,"words":747},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/9 Vitest.md","headers":[]}');export{p as comp,c as data};
